appsmith.onReady(() => {
  startAnalysis();
});
appsmith.onModelChange(() => {
  startAnalysis();
});
function startAnalysis() {
  const m = appsmith.model;

  // Safely retrieve data from model
  const currentCookies = m.cookies || [];
  const currentNetwork = m.networkData || {};
  const currentLogs = m.logs || [];
  const currentScripts = m.scriptAnalysis || {};

  // --- 1. COOKIE ANALYSIS ---
  const cookieStats = analyzeCookies(currentCookies);
  document.getElementById('cookies-3p').textContent = cookieStats.thirdParty;
  document.getElementById('cookies-js').textContent = cookieStats.jsRisk;
  document.getElementById('cookies-sov').textContent = cookieStats.sovScore + '%';

  // --- 2. NETWORK/FINGERPRINTING ANALYSIS ---
  const netStats = analyzeNetwork(currentNetwork, m.persona);
  document.getElementById('net-score').textContent = netStats.score;
  document.getElementById('net-tracker').textContent = netStats.trackers;
  document.getElementById('net-https').textContent = netStats.https > 0 ? netStats.https + '%' : 'Unknown';

  // --- 3. LOGS/SHADOW AI ANALYSIS ---
  const logStats = analyzeLogs(currentLogs);
  document.getElementById('log-shadow').textContent = logStats.shadowCount;
  document.getElementById('log-vol').textContent = logStats.volumeKB + ' KB';
  const sanEl = document.getElementById('log-sanitization');
  sanEl.textContent = logStats.sanitizationActive ? "Observed" : "Missing";
  sanEl.style.color = logStats.sanitizationActive ? "#27ae60" : "#e74c3c";

  // --- 4. SCRIPT/PII ANALYSIS ---
  const scriptStats = analyzeScripts(currentScripts);
  document.getElementById('script-pii').textContent = scriptStats.piiScripts;
  document.getElementById('script-sensitive').textContent = scriptStats.sensitiveScripts;
}
function analyzeCookies(data) {
  if (!Array.isArray(data)) return {
    thirdParty: 0,
    jsRisk: 0,
    sovScore: 0
  };
  const thirdPartyCount = data.filter(c => c.thirdParty === true).length;
  const jsAccessibleCount = data.filter(c => c.httpOnly === false).length;
  const score = data.length > 0 ? Math.round((data.length - thirdPartyCount) / data.length * 100) : 0;
  return {
    thirdParty: thirdPartyCount,
    jsRisk: jsAccessibleCount,
    sovScore: score
  };
}
function analyzeNetwork(data, persona) {
  let score = data.fingerprintingScore || data.fingerprinting || 0;

  // Apply persona multiplier if applicable
  if ((persona || "").toLowerCase().includes("minor") && score > 0.1) {
    score = Math.min(1.0, score * 2.5);
  }
  const trackerCount = (data.trackers || []).length;

  // Attempt to parse HTTPS usage if available in the JSON format
  let httpsTraffic = data.traffic?.httpsTraffic || 0;
  return {
    score: parseFloat(score.toFixed(2)),
    trackers: trackerCount,
    https: Math.round(httpsTraffic * 100)
  };
}
function analyzeLogs(data) {
  if (!Array.isArray(data)) return {
    shadowCount: 0,
    volumeKB: 0,
    sanitizationActive: false
  };
  const unsanctionedAI = ["api.openai.com", "claude.ai", "mistral.ai", "perplexity.ai", "gemini.google.com"];
  let shadowCount = 0;
  let totalBytes = 0;
  let sanitizationFound = false;
  data.forEach(event => {
    // Check Response Headers for Sanitization
    if (event.method === "Network.responseReceived" && event.params && event.params.response) {
      const h = event.params.response.headers || {};
      if (h['x-xss-protection'] || h['X-XSS-Protection']) sanitizationFound = true;
    }

    // Check Request Volume and Shadow AI endpoints
    if (event.method === "Network.requestWillBeSent" && event.params && event.params.request) {
      const url = event.params.request.url || "";
      if (unsanctionedAI.some(ai => url.includes(ai))) shadowCount++;
      const h = event.params.request.headers || {};
      const len = parseInt(h['Content-Length'] || h['content-length'] || 0);
      totalBytes += len;
    }
  });
  return {
    shadowCount,
    volumeKB: parseFloat((totalBytes / 1024).toFixed(1)),
    sanitizationActive: sanitizationFound
  };
}
function analyzeScripts(data) {
  let piiScripts = 0;
  let sensitiveScripts = 0;

  // Handle nested stringified fileData if passed from Appsmith directly
  let fileData = data.fileData || data;
  if (typeof fileData === 'string') {
    try {
      fileData = JSON.parse(fileData);
    } catch (e) {
      fileData = {};
    }
  }

  // Traverse the script analysis structure: {"domain": {"url": {"PIIs": [], "sensitive PIIs": []}}}
  try {
    Object.values(fileData).forEach(domainObj => {
      if (typeof domainObj === 'object' && domainObj !== null) {
        Object.values(domainObj).forEach(scriptObj => {
          if (scriptObj.PIIs && scriptObj.PIIs.length > 0) piiScripts++;
          if (scriptObj['sensitive PIIs'] && scriptObj['sensitive PIIs'].length > 0) sensitiveScripts++;
        });
      }
    });
  } catch (e) {
    console.error("Error parsing script analysis data", e);
  }
  return {
    piiScripts,
    sensitiveScripts
  };
}

